import os
from cryptography.fernet import Fernet

def generate_key():
    return Fernet.generate_key()

def load_key(key_path):
    with open(key_path, 'rb') as file:
        return file.read()

def save_key(key, key_path):
    with open(key_path, 'wb') as file:
        file.write(key)

def encrypt_credit_card(credit_card_number, key):
    fernet = Fernet(key)
    encrypted_card = fernet.encrypt(credit_card_number.encode())
    return encrypted_card

def decrypt_credit_card(encrypted_card, key):
    fernet = Fernet(key)
    decrypted_card = fernet.decrypt(encrypted_card).decode()
    return decrypted_card

# Example usage
if __name__ == "__main__":
    key_path = 'encryption_key.key'
    
    # Generate and save a new key if it doesn't exist
    if not os.path.exists(key_path):
        key = generate_key()
        save_key(key, key_path)
    else:
        key = load_key(key_path)

    credit_card_number = "1234-5678-9012-3456"
    encrypted_card = encrypt_credit_card(credit_card_number, key)
    print("Encrypted Card:", encrypted_card)

    decrypted_card = decrypt_credit_card(encrypted_card, key)
    print("Decrypted Card:", decrypted_card)